// Dev server: runs the asset watcher (sass + esbuild) and Eleventy --serve
// side by side. Dependency-free so we don't pull in concurrently/npm-run-all.
// The TOC is generated by the `prestart` npm hook before this runs.
import { spawn } from 'child_process';
import process from 'process';

const isWindows = process.platform === 'win32';
const npx = isWindows ? 'npx.cmd' : 'npx';

const children = [];

function run(command, args, label) {
	const child = spawn(command, args, {
		stdio: 'inherit',
		shell: isWindows,
		cwd: process.cwd()
	});
	child.on('exit', code => {
		// If either long-running process dies, tear the whole dev server down so
		// the user isn't left with half a pipeline running.
		if (code !== 0 && code !== null) {
			console.error(`[dev] ${label} exited with code ${code}; shutting down.`);
		}
		shutdown(code ?? 0);
	});
	children.push(child);
	return child;
}

let shuttingDown = false;
function shutdown(code) {
	if (shuttingDown) return;
	shuttingDown = true;
	for (const child of children) {
		if (!child.killed) {
			try {
				child.kill();
			} catch {
				/* already gone */
			}
		}
	}
	process.exit(code);
}

process.on('SIGINT', () => shutdown(0));
process.on('SIGTERM', () => shutdown(0));

// Compile assets and keep recompiling on change.
run('node', ['build-assets.mjs', '--watch'], 'assets');
// Serve the site (port/watch options come from eleventy.config.js).
run(npx, ['@11ty/eleventy', '--serve'], 'eleventy');
